mapper.select:
SELECT b.*, u.unit_name as unitName FROM audit_plan_batch b
LEFT JOIN audit_object_unit u ON b.unit_id = u.unit_id WHERE 1=1
 AND (b.batch_id LIKE CONCAT('%',#{keyword},'%') OR b.batch_name LIKE CONCAT('%',#{keyword},'%'))
 AND b.plan_type = #{planType}
 AND b.year = #{year}
 AND b.approval_status = #{approvalStatus}
ORDER BY b.create_time DESC

mapper.update:
UPDATE audit_plan_batch SET batch_name=#{batchName}, plan_type=#{planType}, year=#{year}, project_count=#{projectCount},
start_date=#{startDate}, end_date=#{endDate}, unit_id=#{unitId}, leader_id=#{leaderId},
project_amount=#{projectAmount}, fund_source=#{fundSource}, update_time=NOW() WHERE batch_id=#{batchId}
